  @Test
  public void test_testClashingResolved() throws Exception {
    // Array<T>.myFunction<T extends Int>(T, List<T>)
    Tuples._2<FunctionIdBuilder, LegacyFunctionIdBuilder> first = buildIds("Array<0>", ListSequence.fromListAndArray(new ArrayList<String>(), "0", "List<0>"), ListSequence.fromListAndArray(new ArrayList<String>(), "Int"));
    // Array<T>.myFunction<T extends Double>(T, List<T>)
    Tuples._2<FunctionIdBuilder, LegacyFunctionIdBuilder> second = buildIds("Array<0>", ListSequence.fromListAndArray(new ArrayList<String>(), "0", "List<0>"), ListSequence.fromListAndArray(new ArrayList<String>(), "Double"));

    SNode node1 = new SNode(new InvalidConcept("StubConcept"));
    SNode node2 = new SNode(new InvalidConcept("StubConcept"));

    // First, check we indeed have a clash on the previous state
    node1.setId(KotlinId.kotlinId(first._1().build()));
    node2.setId(KotlinId.kotlinId(second._1().build()));

    StringBasedNodeIdMap map = new StringBasedNodeIdMap();
    map.put(node1.getNodeId(), node1);
    map.put(node2.getNodeId(), node2);

    // node2 replaced node1 for both ids
    Assert.assertSame(map.get(node1.getNodeId()), node2);
    Assert.assertSame(map.get(node2.getNodeId()), node2);

    // Then, we check with the new map things work out
    first._0().applyOn(node1);
    second._0().applyOn(node2);

    map = new KotlinStringBasedNodeIdMap();
    map.put(node1.getNodeId(), node1);
    map.put(node2.getNodeId(), node2);

    Assert.assertSame(map.get(node1.getNodeId()), node1);
    Assert.assertSame(map.get(node2.getNodeId()), node2);
    Assert.assertNotSame(map.get(node1.getNodeId()), node2);
    Assert.assertNotSame(map.get(node2.getNodeId()), node1);
  }
